"use client";

import Image from "next/image";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { useEffect, useState } from "react";
import { ArrowUpRight, Menu, X } from "lucide-react";
import { cn } from "@/lib/utils";

const navItems = [
  { label: "Home", path: "/" },
  { label: "Company", path: "/about" },
  { label: "Products", path: "/products" },
  { label: "Services", path: "/services" },
  { label: "AI Automation", path: "/ai-automation" },
  { label: "Careers", path: "/careers" },
  { label: "Contact", path: "/contact" }
];

const Navbar = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const pathname = usePathname();

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 16);
    handleScroll();
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    setIsMobileMenuOpen(false);
  }, [pathname]);

  const isActive = (path: string) => pathname === path;

  return (
    <nav
      className={cn(
        "fixed left-0 right-0 top-0 z-50 border-b border-border/80 bg-background/95 backdrop-blur-xl transition-shadow duration-300",
        isScrolled && "shadow-soft"
      )}
    >
      <div className="container mx-auto px-4 lg:px-8">
        <div className="flex h-20 items-center justify-between">
          <Link href="/" className="flex items-center gap-3" aria-label="Lumentix Solutions home">
            <Image
              src="/lumentix-logo.png"
              alt="Lumentix Solutions"
              width={156}
              height={48}
              priority
              className="h-12 w-auto object-contain"
            />
          </Link>

          <div className="hidden items-center gap-1 xl:flex">
            {navItems.map((item) => (
              <Link
                key={item.label}
                href={item.path}
                className={cn(
                  "px-3 py-2 text-sm font-semibold text-muted-foreground transition-colors hover:text-foreground",
                  isActive(item.path) && "border-b-2 border-primary text-foreground"
                )}
              >
                {item.label}
              </Link>
            ))}
          </div>

          <div className="hidden items-center gap-3 xl:flex">
            <Link
              href="/contact"
              className="inline-flex h-10 items-center justify-center border border-border bg-background px-4 text-sm font-semibold text-foreground transition-colors hover:bg-muted"
            >
              Start AI Project
            </Link>
            <Link
              href="/login"
              className="inline-flex h-10 items-center justify-center border border-primary bg-primary px-4 text-sm font-semibold text-primary-foreground transition-colors hover:bg-primary-hover"
            >
              Employee Login
              <ArrowUpRight className="ml-2 h-4 w-4" />
            </Link>
          </div>

          <button
            onClick={() => setIsMobileMenuOpen((open) => !open)}
            className="inline-flex h-10 w-10 items-center justify-center border border-border text-foreground transition-colors hover:bg-muted xl:hidden"
            aria-label="Toggle navigation"
            aria-expanded={isMobileMenuOpen}
          >
            {isMobileMenuOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
          </button>
        </div>
      </div>

      {isMobileMenuOpen ? (
        <div className="border-t border-border bg-background xl:hidden">
          <div className="container mx-auto grid gap-2 px-4 py-4">
            {navItems.map((item) => (
              <Link
                key={item.label}
                href={item.path}
                className={cn(
                  "border border-transparent px-4 py-3 text-sm font-semibold text-muted-foreground transition-colors hover:border-border hover:text-foreground",
                  isActive(item.path) && "border-border bg-muted text-foreground"
                )}
              >
                {item.label}
              </Link>
            ))}
            <Link
              href="/login"
              className="mt-2 inline-flex h-11 items-center justify-center border border-primary bg-primary px-4 text-sm font-semibold text-primary-foreground"
            >
              Employee Login
            </Link>
            <Link
              href="/contact"
              className="inline-flex h-11 items-center justify-center border border-border px-4 text-sm font-semibold text-foreground"
            >
              Start AI Project
            </Link>
          </div>
        </div>
      ) : null}
    </nav>
  );
};

export default Navbar;
